const http = require('http');
const url = require('url');

class Plugin {
  constructor(name) {
    this.name = name;
  }

  preProcess(req, res, next) {}
  postProcess(req, res, next) {}
}

class APIGateway {
  constructor(port) {
    this.port = port;
    this.plugins = [];
    this.configFile = 'config.json';
  }

  loadPlugins(config) {
    if (config && config.plugins) {
      config.plugins.forEach((pluginConfig) => {
        try {
          const pluginName = pluginConfig.name;
          let pluginCode;
          if (pluginConfig.codeFromConfig) {
            pluginCode = pluginConfig.code;
          } else if (process.env[`${pluginName}_PLUGIN_CODE`]) {
            pluginCode = process.env[`${pluginName}_PLUGIN_CODE`];
          }
          const plugin = new Plugin(pluginName);
          plugin.pluginCode = pluginCode;
          this.plugins.push(plugin);
        } catch (error) {
          console.error(`Error loading plugin ${pluginConfig.name}:`, error);
        }
      });
    }
  }

  init() {
    require(this.configFile).then((config) => {
      this.loadPlugins(config);
      const server = http.createServer(async (req, res) => {
        for (const plugin of this.plugins) {
          if (plugin.preProcess) {
            await plugin.preProcess(req, res);
          }
        }
        let body = '';
        req.on('data', (chunk) => {
          body += chunk.toString();
        });
        req.on('end', () => {
          const { pathname } = url.parse(req.url).pathname;
          if (pathname === '/') {
            res.writeHead(200, {'Content-Type': 'text/plain'});
            res.end('Hello World\n');
          }
          for (const plugin of this.plugins) {
            if (plugin.postProcess) {
              await plugin.postProcess(req, res);
            }
          }
        });
      }).listen(this.port, () => {
        console.log(`API Gateway listening on port ${this.port}`);
      });
    }).catch((error) => {
      console.error('Error loading config:', error);
    });
  }
}

const apiGateway = new APIGateway(3000);
apiGateway.init();